<?php include __DIR__.'/_init.php';$s=current_student();$q=$db->prepare('SELECT c.*,co.title FROM certificates c JOIN courses co ON co.id=c.course_id WHERE c.student_id=?');$q->execute([$s['id']]);$rows=$q->fetchAll(); ?><h3>My Certificates</h3><?php foreach($rows as $r):?><div><?=e($r['title'])?> - <?=e($r['verification_id'])?> - <a href="<?=e($r['certificate_file'])?>">Download</a></div><?php endforeach;?>
